mepc_setup:       
                  la x12, init
                  csrw 0x341, x12

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_machine_mode:
                  li x12, 0x1800
                  csrw 0x300, x12 # MSTATUS
                  li x12, 0x0
                  csrw 0x304, x12 # MIE
                  li x22, 0x8ffffffc
                  li x12, 0x300
                  slli x12, x12, 8
                  addi x12, x12, 0x3
                  sw x12, 0(x22)
