                  li x12, 0x0
                  slli x12, x12, 8
                  addi x12, x12, 0x0
                  sw x12, 0(x22)
                  j main
test_done:        
                  li x22, 0x8ffffff8
                  li x12, 0x0
                  slli x12, x12, 8
                  addi x12, x12, 0x1
                  sw x12, 0(x22)
                  ecall

